// AUTO-GENERATED DRAFT SCREEN: CryptoForgotPasswordScreen

import React, { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { useForgotPassword } from '@/lib/trpc/hooks'; // Assuming tRPC hook exists for password reset functionality

/**
 * Props for the CryptoForgotPasswordScreen component.
 * Currently, no specific props are required.
 */
interface CryptoForgotPasswordScreenProps {}

/**
 * CryptoForgotPasswordScreen component for handling password reset requests.
 * It provides a form for users to enter their email address to receive a password reset link.
 * The component integrates with tRPC for backend communication, manages loading states,
 * and displays success or error messages.
 */
const CryptoForgotPasswordScreen: React.FC<CryptoForgotPasswordScreenProps> = () => {
  // State to manage the email input field value
  const [email, setEmail] = useState<string>('');
  // State to store and display success messages to the user
  const [message, setMessage] = useState<string | null>(null);
  // State to store and display error messages to the user
  const [error, setError] = useState<string | null>(null);

  // Placeholder for the tRPC forgot password mutation hook.
  // This hook would typically be generated by tRPC based on your API schema.
  // It handles the asynchronous request to send a password reset email.
  const { mutate: forgotPassword, isLoading } = useForgotPassword({
    // Callback for successful password reset request
    onSuccess: () => {
      setMessage('Password reset link sent to your email. Please check your inbox.');
      setError(null); // Clear any previous errors
    },
    // Callback for failed password reset request
    onError: (err) => {
      // Display a user-friendly error message
      setError(err.message || 'Failed to send reset link. Please try again later.');
      setMessage(null); // Clear any previous success messages
    },
  });

  /**
   * Handles the form submission event.
   * Prevents default form submission and triggers the tRPC mutation.
   * @param e The form event.
   */
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault(); // Prevent default browser form submission
    setError(null); // Clear previous errors
    setMessage(null); // Clear previous messages

    // Basic client-side validation for email presence
    if (!email) {
      setError('Please enter your email address to proceed.');
      return;
    }

    // Execute the tRPC mutation to request a password reset
    forgotPassword({ email });
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-background dark:bg-gray-900 p-4">
      <Card className="w-full max-w-md p-6 space-y-4 md:p-8 shadow-lg rounded-lg">
        <CardHeader className="text-center">
          <CardTitle className="text-3xl font-extrabold text-gray-900 dark:text-white">Forgot Password</CardTitle>
          <CardDescription className="text-md text-gray-600 dark:text-gray-400 mt-2">
            Enter your email address below and we'll send you a link to reset your password.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid gap-2">
              <Label htmlFor="email" className="text-sm font-medium text-gray-700 dark:text-gray-300">Email Address</Label>
              <Input
                id="email"
                type="email"
                placeholder="you@example.com"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                aria-label="Email address for password reset"
                className="mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm dark:bg-gray-700 dark:border-gray-600 dark:text-white"
              />
            </div>
            {/* Display success message if available */}
            {message && (
              <p className="text-green-600 dark:text-green-400 text-sm text-center font-medium">
                {message}
              </p>
            )}
            {/* Display error message if available */}
            {error && (
              <p className="text-red-600 dark:text-red-400 text-sm text-center font-medium">
                {error}
              </p>
            )}
            <Button
              type="submit"
              className="w-full py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 dark:bg-indigo-500 dark:hover:bg-indigo-600"
              disabled={isLoading}
            >
              {isLoading ? 'Sending Reset Link...' : 'Send Reset Link'}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
};

export default CryptoForgotPasswordScreen;
